function removeDuplicates(s, k) {
    let stack = [];
    for (let c of s) {
        if (stack.length > 0 && stack[stack.length - 1][0] === c) {
            stack[stack.length - 1][1]++;
            if (stack[stack.length - 1][1] === k) stack.pop();
        } else {
            stack.push([c, 1]);
        }
    }
    return stack.map(([c, n]) => c.repeat(n)).join('');
}
